#!/usr/bin/env node
/*
 * Generates `tailwind.active_theme.css` at the project root with a single
 * @import pointing at the active theme's `theme.css`. Reads `FLS_THEME` from
 * the environment (defaulting to `default`).
 *
 * Invoked by the `tailwind_build` / `tailwind_watch` npm scripts immediately
 * before Tailwind compiles `tailwind.input.css`. The generated file is
 * referenced as `@import "./tailwind.active_theme.css";` from the input and
 * is intentionally gitignored.
 *
 * Cascade contract (Phase 2 of themable-implementations):
 *   - `tailwind.input.css` imports the default theme as the always-on baseline.
 *   - It then imports `tailwind.components.css`.
 *   - It then imports the generated `tailwind.active_theme.css` so the active
 *     theme's tokens win on cascade. When FLS_THEME=default, this import is a
 *     re-import of the same file (a no-op against the baseline).
 */

import { existsSync, writeFileSync } from "node:fs";
import { join } from "node:path";

const slug = process.env.FLS_THEME || "default";

if (!/^[a-z0-9_-]+$/i.test(slug)) {
    console.error(
        `write-active-theme: refusing to template invalid FLS_THEME=${JSON.stringify(slug)}; ` +
            `slug must match /^[a-z0-9_-]+$/i.`,
    );
    process.exit(1);
}

const importPath = `./freedom_ls/themes/${slug}/static/themes/${slug}/theme.css`;
const resolvedPath = join(process.cwd(), importPath);

// Fail loudly here rather than letting Tailwind error mid-build on a missing
// @import — much clearer signal that the FLS_THEME slug is wrong.
if (!existsSync(resolvedPath)) {
    console.error(
        `write-active-theme: FLS_THEME=${JSON.stringify(slug)} but no theme.css ` +
            `found at ${resolvedPath}. Check the slug or add the theme directory.`,
    );
    process.exit(1);
}

const contents = `/* Generated by scripts/write-active-theme.mjs — do not edit by hand. */\n@import "${importPath}";\n`;

writeFileSync(join(process.cwd(), "tailwind.active_theme.css"), contents);
